/*
 * Boolean Functions Implementation in C
 * Generates truth tables, identifies minterms/maxterms,
 * and converts to canonical SOP/POS forms
 */

#include <stdio.h>
#include <math.h>
#include <string.h>

#define MAX_VARS 4
#define MAX_TERMS 16

// Function to evaluate Boolean expression for given inputs
// F(A,B,C) = A'BC + AB'C + ABC
int evaluateFunction(int A, int B, int C) {
 int term1 = (!A) && B && C; // A'BC
 int term2 = A && (!B) && C; // AB'C 
 int term3 = A && B && C; // ABC
 return term1 || term2 || term3;
}

// Generate minterm notation from binary
void getMinterm(int index, int numVars, char *output) {
 char vars[] = {'A', 'B', 'C', 'D'};
 int pos = 0;

 for (int i = numVars - 1; i >= 0; i--) {
 if ((index >> i) & 1) {
 output[pos++] = vars[numVars - 1 - i];
 } else {
 output[pos++] = vars[numVars - 1 - i];
 output[pos++] = '\'';
 }
 }
 output[pos] = '\0';
}

// Generate maxterm notation from binary
void getMaxterm(int index, int numVars, char *output) {
 char vars[] = {'A', 'B', 'C', 'D'};
 int pos = 0;

 output[pos++] = '(';
 for (int i = numVars - 1; i >= 0; i--) {
 if ((index >> i) & 1) {
 output[pos++] = vars[numVars - 1 - i];
 output[pos++] = '\'';
 } else {
 output[pos++] = vars[numVars - 1 - i];
 }
 if (i > 0) output[pos++] = '+';
 }
 output[pos++] = ')';
 output[pos] = '\0';
}

void generateTruthTable(int numVars) {
 int numCombinations = pow(2, numVars);
 char varNames[] = {'A', 'B', 'C', 'D'};
 int minterms[MAX_TERMS], maxterms[MAX_TERMS];
 int minCount = 0, maxCount = 0;

 // Print header
 printf("\n========================================\n");
 printf("Truth Table: F(A,B,C) = A'BC + AB'C + ABC\n");
 printf("========================================\n");

 for (int i = 0; i < numVars; i++) {
 printf("%c ", varNames[i]);
 }
 printf("| F\n");
 printf("----------------------------------------\n");

 // Generate all combinations
 for (int i = 0; i < numCombinations; i++) {
 // Extract individual bits
 int A = (i >> 2) & 1;
 int B = (i >> 1) & 1;
 int C = i & 1;

 // Evaluate function
 int result = evaluateFunction(A, B, C);

 // Print row
 printf("%d %d %d | %d\n", A, B, C, result);

 // Collect minterms/maxterms
 if (result == 1) {
 minterms[minCount++] = i;
 } else {
 maxterms[maxCount++] = i;
 }
 }

 // Print results
 printf("\n========================================\n");
 printf("Results:\n");
 printf("========================================\n");

 // Minterms
 printf("Minterms (F=1): ");
 printf("Σ(%d", minterms[0]);
 for (int i = 1; i < minCount; i++) {
 printf(", %d", minterms[i]);
 }
 printf(")\n");

 // Maxterms
 printf("Maxterms (F=0): ");
 printf("Π(%d", maxterms[0]);
 for (int i = 1; i < maxCount; i++) {
 printf(", %d", maxterms[i]);
 }
 printf(")\n");

 // Canonical SOP
 printf("\nCanonical SOP: F = ");
 char term[10];
 getMinterm(minterms[0], numVars, term);
 printf("%s", term);
 for (int i = 1; i < minCount; i++) {
 getMinterm(minterms[i], numVars, term);
 printf(" + %s", term);
 }
 printf("\n");

 // Canonical POS
 printf("Canonical POS: F = ");
 getMaxterm(maxterms[0], numVars, term);
 printf("%s", term);
 for (int i = 1; i < maxCount; i++) {
 getMaxterm(maxterms[i], numVars, term);
 printf(" * %s", term);
 }
 printf("\n");
}

// Demonstrate algebraic simplification
void demonstrateSimplification() {
 printf("\n========================================\n");
 printf("Algebraic Simplification Demo\n");
 printf("========================================\n");
 printf("Given: F = x'y'z + x'yz + xy'\n\n");
 printf("Step 1: Factor x'z from first two terms\n");
 printf(" F = x'z(y' + y) + xy'\n\n");
 printf("Step 2: Apply Complement Law (y' + y = 1)\n");
 printf(" F = x'z(1) + xy'\n\n");
 printf("Step 3: Apply Identity Law (x'z(1) = x'z)\n");
 printf("Final: F = x'z + xy'\n");
 printf("========================================\n");
}

int main() {
 printf("BOOLEAN FUNCTIONS - TRUTH TABLE GENERATOR\n");
 printf("========================================\n");

 // Generate truth table for 3 variables
 generateTruthTable(3);

 // Demonstrate algebraic simplification
 demonstrateSimplification();

 return 0;
}
